// /frontend/src/components/WeatherApp.jsx
import React, { useEffect, useState } from "react";
import WeatherOverlay from "./WeatherOverlay";
import Radar from "./Radar";
import Forecast from "./Forecast";
import BottomBar from "./BottomBar";
import SearchSection from "./SearchSection";

const DEFAULT_PLACE = { name: "Atlanta, US", lat: 33.7490, lon: -84.3880 };
const API_BASE = process.env.REACT_APP_API_BASE || "http://127.0.0.1:8000";

const isFiniteNum = (n) => typeof n === "number" && isFinite(n);

export default function WeatherApp() {
  // Selected city (SearchSection should call onSelect with {name, lat, lon})
  const [place, setPlace] = useState(DEFAULT_PLACE);

  // Weather data returned from backend
  const [weather, setWeather] = useState({
    current: null,
    hourly: [],
    daily: [],
    summary: "",
  });
  const [loading, setLoading] = useState(false);
  const [err, setErr] = useState("");

  // Search callback (keep minimal; SearchSection handles favorites/restore)
  function handleSearchSelect(p) {
    setPlace({
      name: p?.name || DEFAULT_PLACE.name,
      lat: isFiniteNum(p?.lat) ? p.lat : DEFAULT_PLACE.lat,
      lon: isFiniteNum(p?.lon) ? p.lon : DEFAULT_PLACE.lon,
    });
  }

  // Fetch from backend whenever city changes — send { location } per your server
  useEffect(() => {
    let abort = false;

    async function run() {
      try {
        setLoading(true);
        setErr("");

        const res = await fetch(`${API_BASE}/api/weather/current`, {
          method: "POST",
          headers: { "Content-Type": "application/json" },
          body: JSON.stringify({ location: place.name }),
        });

        if (!res.ok) {
          const text = await res.text().catch(() => "");
          throw new Error(`HTTP ${res.status} ${text || res.statusText}`);
        }

        const data = await res.json();
        console.debug("weather payload:", data);

        // Normalize to what the UI expects
        const root = data?.weather ?? data;
        const normalized = {
          current: root.current ?? null,
          hourly: Array.isArray(root.hourly)
            ? root.hourly
            : Array.isArray(root?.hourly?.list)
            ? root.hourly.list
            : Array.isArray(root?.hourly?.data)
            ? root.hourly.data
            : [],
          daily: Array.isArray(root.daily)
            ? root.daily
            : Array.isArray(root?.daily?.list)
            ? root.daily.list
            : Array.isArray(root?.daily?.data)
            ? root.daily.data
            : [],
          summary:
            typeof data.summary === "string"
              ? data.summary
              : root.summary ?? "",
        };

        if (!abort) setWeather(normalized);
      } catch (e) {
        if (!abort) setErr(e.message || "Failed to load weather");
      } finally {
        if (!abort) setLoading(false);
      }
    }

    if (place?.name) run();
    return () => {
      abort = true;
    };
  }, [place?.name]);

  return (
    <div className="relative min-h-screen flex flex-col bg-white overflow-hidden">
      {/* Dynamic background overlays */}
      <WeatherOverlay />

      {/* Search */}
      <header className="px-4 pt-4">
        <SearchSection
          defaultValue={place?.name || ""}
          onSelect={handleSearchSelect}
        />
      </header>

      {/* Small status line (remove if you don't want it) */}
      {loading && (
        <div className="px-4 mt-2 text-xs text-gray-600">Loading weather…</div>
      )}
      {!loading && err && (
        <div className="px-4 mt-2 text-xs text-red-600">{err}</div>
      )}

      {/* Current city label */}
      <section className="px-4 mt-3 mb-2">
        <div className="text-sm text-gray-700">
          <span className="font-medium text-gray-900">{place?.name}</span>
        </div>
      </section>

      {/* Radar — wrap in a fixed-height box so it never stretches */}
      <section className="px-4 mb-24">
        <div className="h-80 md:h-96 rounded-2xl overflow-hidden">
          <Radar
            center={[
              isFiniteNum(place?.lat) ? place.lat : DEFAULT_PLACE.lat,
              isFiniteNum(place?.lon) ? place.lon : DEFAULT_PLACE.lon,
            ]}
            zoom={6}
            // Let the wrapper control height:
            className="w-full h-full"
          />
        </div>
      </section>

      {/* Forecast — now fed with normalized data */}
      <Forecast
        current={weather.current}
        hourly={weather.hourly}
        daily={weather.daily}
        summary={weather.summary}
      />

      {/* Bottom bar (wired to router) */}
      <BottomBar />
    </div>
  );
}
